import React, { useState } from 'react';
import { FaHeart, FaRegHeart } from 'react-icons/fa';
import '../styles/figma-design.css';

export default function FigmaChat() {
    const [messages, setMessages] = useState([
        { id: 1, name: 'Женя', text: 'Всем привет', likes: 567, liked: false },
        { id: 2, name: 'Женя', text: 'Какое-то сообщение длиннее, чем 1 строка.', likes: 11, liked: false },
        { id: 3, name: 'Женя', text: 'Всем привет', likes: 0, liked: false },
        { id: 4, name: 'Женя', text: 'Всем привет', likes: 15, liked: true },
        { id: 5, name: 'Женя', text: 'Всем привет', likes: 42, liked: false },
        { id: 6, name: 'Женя', text: 'Всем привет', likes: 0, liked: false },
    ]);
    const [activeTab, setActiveTab] = useState('chat');
    const [newMessage, setNewMessage] = useState('');

    const handleLike = (id) => {
        setMessages(messages.map(msg => 
            msg.id === id 
                ? { ...msg, liked: !msg.liked, likes: msg.liked ? msg.likes - 1 : msg.likes + 1 }
                : msg
        ));
    };

    const handleSendMessage = () => {
        if (newMessage.trim()) {
            setMessages([
                ...messages,
                {
                    id: messages.length + 1,
                    name: 'Вы',
                    text: newMessage,
                    likes: 0,
                    liked: false
                }
            ]);
            setNewMessage('');
        }
    };

    return (
        <div className="chat-25">
            <div style={{ width: '100%' }}>
                <div className="forum_tabs-28">
                    <div 
                        className={`property-1-${activeTab === 'chat' ? 'active' : 'unactive'}`}
                        onClick={() => setActiveTab('chat')}
                    >
                        <p className="text-30">Чат</p>
                        {activeTab === 'chat' && <div className="underline-31"></div>}
                    </div>
                    <div 
                        className={`property-1-${activeTab === 'qa' ? 'active' : 'unactive'}`}
                        onClick={() => setActiveTab('qa')}
                    >
                        <p className="text-33">Вопрос / ответ</p>
                        {activeTab === 'qa' && <div className="underline-31"></div>}
                    </div>
                </div>

                <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
                    {messages.map((msg) => (
                        <div key={msg.id} className={`property-1-${msg.liked ? 'liked' : 'default'}`}>
                            <div className="name_message-37">
                                <p className="text-38">{msg.name}</p>
                                <p className="text-39">{msg.text}</p>
                            </div>
                            <div 
                                className="property-1-like"
                                onClick={() => handleLike(msg.id)}
                            >
                                {msg.liked ? <FaHeart color="#fff" /> : <FaRegHeart color="#999" />}
                                <p className="text-43">{msg.likes}</p>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="scroll-bar">
                    <div className="bg-85"></div>
                    <div className="scroll-86"></div>
                </div>

                <div className="property-1-default" style={{ marginTop: '16px', padding: '8px' }}>
                    <input
                        type="text"
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        placeholder="Хотите отправить сообщение? Кликните на эту кнопку"
                        style={{
                            flex: 1,
                            background: 'transparent',
                            border: 'none',
                            color: 'white',
                            outline: 'none',
                            fontFamily: 'var(--font-family-proxima-nova)'
                        }}
                        onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                    />
                    <button 
                        onClick={handleSendMessage}
                        className="text-88"
                        style={{ padding: '8px 20px', fontSize: '14px' }}
                    >
                        Отправить
                    </button>
                </div>
            </div>
        </div>
    );
}
